/**
 * Deterministic synthetic daily candles (no randomness — the same rows render
 * on every build). A fixed repeating daily-return pattern scaled per ticker:
 * `scale` ≈ how volatile the fictional stock is.
 */
function demoCandles(startPrice: number, scale: number, days = 130): CandleData[] {
  // ~1% average absolute daily move at scale 1 — an ordinary large-cap.
  const pattern = [0.8, -0.6, 1.2, -0.9, 0.4, -1.1, 0.7, 1.5, -0.5, -1.3, 0.9, 0.3];
  const candles: CandleData[] = [];
  let close = startPrice;
  const dayMs = 24 * 60 * 60 * 1000;
  const start = Date.UTC(2026, 0, 5); // fixed, declared demo epoch
  for (let i = 0; i < days; i++) {
    const retPct = pattern[i % pattern.length] * scale;
    const open = close;
    close = Math.round(open * (1 + retPct / 100) * 100) / 100;
    const hi = Math.max(open, close);
    const lo = Math.min(open, close);
    const t = start + i * dayMs;
    candles.push({
      time: Math.floor(t / 1000),
      date: new Date(t).toISOString().slice(0, 10),
      open,
      high: Math.round(hi * 1.004 * 100) / 100,
      low: Math.round(lo * 0.996 * 100) / 100,
      close,
      volume: 1_000_000 + (i % 7) * 50_000,
    });
  }
  return candles;
}

