// ── engine output → plain rows ───────────────────────────────────────────────

export interface TradeShowcaseRow {
  ticker: string;
  volEdge: number | null;
  quality: number | null;
  regime: number | null;
  infoEdge: number | null;
  composite: number | null;
  /** The engine's own convergence-gate string, verbatim (composite.ts:159-170). */
  gate: string;
  positionSizePct: number;
  /** Engine strategy suggestion — rendered only when the engine sizes > 0. */
  strategy: string;
  suggestedDte: number;
}

const r1 = (v: number | null): number | null => (v == null ? null : Math.round(v * 10) / 10);

function toRow(input: ConvergenceInput): TradeShowcaseRow {
  const res = scoreAll(input);
  return {
    ticker: input.symbol,
    volEdge: r1(res.vol_edge.score),
    quality: r1(res.quality.score),
    regime: r1(res.regime.score),
    infoEdge: r1(res.info_edge.score),
    composite: r1(res.composite.score),
    gate: res.composite.convergence_gate,
    positionSizePct: res.composite.position_size_pct,
    strategy: res.strategy_suggestion.suggested_strategy,
    suggestedDte: res.strategy_suggestion.suggested_dte,
  };
}

/** The three demo rows — computed by the real engine on the declared inputs. */
export const TRADE_SHOWCASE_ROWS: TradeShowcaseRow[] = [ACME, GLOBEX, INITECH].map(toRow);

/** The engine's survival-brake declaration for the shared demo macro (all rows
 *  see the same market state, like a real scan) — rendered verbatim. */
export const TRADE_SHOWCASE_BRAKE: { state: 'OFF' | 'ON' | 'UNVERIFIED'; declaration: string } =
  scoreAll(ACME).composite.regime_brake;
